"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[46793],{84219(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>s,default:()=>h,frontMatter:()=>o,metadata:()=>n,toc:()=>f});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases/economic-benefits-from-use-of-a-wind-507f5f27d5","title":"Economic Benefits from Use of a Windfarm (IFRS 16)","description":"December 2021","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases/Economic Benefits from Use of a Windfarm (IFRS 16).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/economic-benefits-from-use-of-a-wind-507f5f27d5","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/economic-benefits-from-use-of-a-wind-507f5f27d5","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"id":"economic-benefits-from-use-of-a-wind-507f5f27d5","title":"Economic Benefits from Use of a Windfarm (IFRS 16)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/economic-benefits-from-use-of-a-wind-507f5f27d5","sidebar_position":3},"sidebar":"knowledgeSidebar","previous":{"title":"Definition of a Lease\u2014Substitution Rights (IFRS 16","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-substitution-r-1bd7c8fed7"},"next":{"title":"Lessee\u2019s Incremental Borrowing Rate (IFRS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/lessee-s-incremental-borrowing-rate--acfd908f14"}}');var a=i(74848),r=i(28453);let o={id:"economic-benefits-from-use-of-a-wind-507f5f27d5",title:"Economic Benefits from Use of a Windfarm (IFRS 16)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/economic-benefits-from-use-of-a-wind-507f5f27d5",sidebar_position:3},s="Economic Benefits from Use of a Windfarm (IFRS 16)",c={},f=[];function d(e){let t={h1:"h1",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"economic-benefits-from-use-of-a-windfarm-ifrs-16",children:"Economic Benefits from Use of a Windfarm (IFRS 16)"})}),"\n",(0,a.jsx)(t.p,{children:"December 2021"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about whether, applying paragraph B9(a) of IFRS 16, an electricity retailer (retailer) has the right to obtain substantially all the economic benefits from use of a windfarm throughout the term of an agreement with a windfarm generator (supplier). In the fact pattern described in the request:"}),"\n",(0,a.jsx)(t.p,{children:"a. the retailer and supplier are registered participants in an electricity market, in which customers and suppliers are unable to enter into contracts directly with each other for the purchase and sale of electricity. Instead, customers and suppliers make such purchases and sales via the market\u2019s electricity grid, the spot price for which is set by the market operator. The retailer therefore purchases electricity from the grid.\nb. the retailer enters into an agreement with the supplier. The agreement:\ni. swaps the spot price per megawatt of electricity the windfarm supplies to the grid during the 20-year term of the agreement for a fixed price per megawatt, and is settled net in cash. In effect, the supplier receives a fixed price per megawatt for the electricity it supplies to the grid during the period of the agreement and the retailer settles with the supplier the difference between that fixed price and the spot prices per megawatt for that volume of electricity.\nii. transfers to the retailer all renewable energy credits that accrue from use of the windfarm."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 9 of IFRS 16 states that \u2018a contract is, or contains, a lease if the contract conveys the right to control the use of an identified asset for a period of time in exchange for consideration\u2019. To control the use of an identified asset for a period of time, the customer\u2014throughout the period of use\u2014must have both the right to obtain substantially all the economic benefits from use of the identified asset and the right to direct the use of that asset (paragraph B9 of IFRS 16)."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph B21 of IFRS 16 specifies that \u2018a customer can obtain economic benefits from use of an asset directly or indirectly in many ways, such as by using, holding or sub-leasing the asset. The economic benefits from use of an asset include its primary output and by-products (including potential cash flows derived from these items), and other economic benefits from using the asset that could be realised from a commercial transaction with a third party\u2019."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the fact pattern described in the request, the economic benefits from use of the windfarm include the electricity it produces (as its primary output) and the renewable energy credits (as a by-product or other economic benefit from use of the windfarm)."}),"\n",(0,a.jsx)(t.p,{children:"The agreement results in the retailer settling with the supplier the difference between the fixed price and the spot prices per megawatt of electricity the windfarm supplies to the grid throughout the 20-year term of the agreement. That agreement, however, conveys neither the right nor the obligation for the retailer to obtain any of the electricity the windfarm produces and supplies to the grid. Although the retailer has the right to obtain the renewable energy credits (which represent a portion of the economic benefits from use of the windfarm), the retailer does not have the right to obtain substantially all the economic benefits from use of the windfarm because it has no right to obtain any of the electricity the windfarm produces throughout the period of the agreement."}),"\n",(0,a.jsx)(t.p,{children:"The Committee therefore concluded that, in the fact pattern described in the request, the retailer does not have the right to obtain substantially all the economic benefits from use of the windfarm. Consequently, the agreement does not contain a lease."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for an entity that enters into an agreement as described in the request to assess whether it has the right to obtain substantially all the economic benefits from use of an identified asset. Consequently, the Committee decided not to add a standard-setting project to the work plan."}),"\n",(0,a.jsx)(t.p,{children:"In considering the request, the Committee noted two other agenda decisions that include explanatory material that may be relevant to the agreement described in this request:"}),"\n",(0,a.jsx)(t.p,{children:"a. the Agenda Decision Meaning of delivery (IFRS 9 Financial Instruments) (August 2005); and\nb. for entities applying the hedge accounting requirements in IFRS 9 or IAS 39 Financial Instruments: Recognition and Measurement, the Agenda Decision Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument (IFRS 9 and IAS 39) (March 2019)."})]})}function h(e={}){let{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,t,i){i.d(t,{R:()=>o,x:()=>s});var n=i(96540);let a={},r=n.createContext(a);function o(e){let t=n.useContext(r);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),n.createElement(r.Provider,{value:t},e.children)}}}]);